415	// reportSkillInstallTopology prints the global and project install layers for
416	// the default ddx package so operators can see whether the project copy exists
417	// or is falling through to the global layer.
418	func reportSkillInstallTopology(projectRoot string) {
419		ctx := context.Background()
420	
421		globalPath := filepath.Join(ddxroot.GlobalDir(), "plugins", "ddx")
422		globalStatus := "missing"
423		if info, err := os.Stat(globalPath); err == nil && info.IsDir() {
424			globalStatus = "ok"
425		}
426	
427		projectPath := filepath.Join(projectRoot, ddxroot.DirName, "plugins", "ddx")
428		projectStatus := "missing"
429		if existingRoot, ok := ddxroot.ExistingPath(ctx, projectRoot); ok {
430			projectPath = filepath.Join(existingRoot, "plugins", "ddx")
431			if _, layer, err := registry.ResolvePlugin(ctx, projectRoot, "ddx"); err == nil {
432				switch layer {
433				case "project":
434					projectStatus = "ok"
435				case "global":
436					projectStatus = "lazy-resolves-to-global"
437				case "baked-in":
438					projectStatus = "missing"
439				}
440			} else if globalStatus == "ok" {
441				projectStatus = "lazy-resolves-to-global"
442			}
443		} else if globalStatus == "ok" {
444			projectStatus = "lazy-resolves-to-global"
445		}
446	
447		fmt.Printf("   Global Install (%s) — %s\n", globalPath, globalStatus)
448		fmt.Printf("   Project Install (%s) — %s\n", projectPath, projectStatus)
449	}
