394	func readWorktreeRegistry(path string) (worktreeRegistry, error) {
395		data, err := os.ReadFile(path)
396		if err != nil {
397			if os.IsNotExist(err) {
398				return worktreeRegistry{}, nil
399			}
400			return worktreeRegistry{}, err
401		}
402		if len(data) == 0 {
403			return worktreeRegistry{}, nil
404		}
405		var registry worktreeRegistry
406		if err := json.Unmarshal(data, &registry); err != nil {
407			return worktreeRegistry{}, err
408		}
409		return registry, nil
410	}
411	
412	func writeWorktreeRegistry(path string, registry worktreeRegistry) error {
413		data, err := json.MarshalIndent(registry, "", "  ")
414		if err != nil {
415			return err
416		}
417		data = append(data, '\n')
418		tmp := path + ".tmp"
419		if err := os.WriteFile(tmp, data, 0o644); err != nil {
420			return err
421		}
422		return os.Rename(tmp, path)
423	}
